 1	import type { FC, ReactNode } from 'react';
 2	
 3	import {
 4	  getGroupVersionKindForResource,
 5	  type K8sGroupVersionKind,
 6	  type K8sModel,
 7	  type K8sResourceKind,
 8	  ResourceIcon,
 9	  ResourceStatus,
10	} from '@openshift-console/dynamic-plugin-sdk';
11	import Status from '@openshift-console/dynamic-plugin-sdk/lib/app/components/status/Status';
12	import { Split, SplitItem } from '@patternfly/react-core';
13	
14	import BreadCrumbs from './BreadCrumb';
15	
16	import './PageHeadings.scss';
17	
18	type PageHeadingsProps = {
19	  model: K8sModel;
20	  namespace?: string;
21	  obj?: K8sResourceKind;
22	  title?: ReactNode;
23	  actions?: ReactNode;
24	  status?: string | ReactNode;
25	  children?: ReactNode;
26	  testId?: string;
27	};
28	
29	export const PageHeadings: FC<PageHeadingsProps> = ({
30	  actions,
31	  children,
32	  model,
33	  namespace,
34	  obj: data,
35	  status,
36	  testId,
37	}) => {
38	  const dataStatus = status ?? data?.status?.phase;
39	  const groupVersionKind = data?.kind && getGroupVersionKindForResource(data);
40	
41	  return (
42	    <div className="pf-v6-c-page__main-section">
43	      <BreadCrumbs model={model} namespace={namespace} />
44	      <span className="co-m-pane__heading co-resource-item">
45	        <h1 className="pf-v6-c-content--h1" data-testid={testId}>
46	          <Split hasGutter>
47	            <SplitItem>
48	              <ResourceIcon
49	                groupVersionKind={groupVersionKind as K8sGroupVersionKind}
50	                className="co-m-resource-icon--lg"
51	              />{' '}
52	              {data?.metadata?.name}
53	              {typeof dataStatus === 'string' && (
54	                <span data-testid="resource-status">
55	                  <ResourceStatus additionalClassNames="hidden-xs">
56	                    <Status status={dataStatus} />
57	                  </ResourceStatus>
58	                </span>
59	              )}
60	            </SplitItem>
61	            {status && typeof status !== 'string' && (
62	              <SplitItem
63	                className="forklift-page-headings__status hidden-xs"
64	                data-testid="plan-status-container"
65	              >
66	                {status}
67	              </SplitItem>
68	            )}
69	          </Split>
70	        </h1>
71	        <Split hasGutter>
72	          <SplitItem>{actions}</SplitItem>
73	        </Split>
74	      </span>
75	      {children}
76	    </div>
77	  );
78	};

